import { Injectable } from '@angular/core';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Character, CharacterListItem } from '../models/character';
import { Observable, catchError, tap, throwError } from 'rxjs';
import { AuthService } from './auth.service';

@Injectable({
  providedIn: 'root'
})
export class CharacterService {
  private baseUrl = 'https://characters.discloud.app/api';

  constructor(
    private http: HttpClient,
    private authService: AuthService
  ) { }

  // Método privado para obter os headers de autorização
  private getAuthHeaders(): HttpHeaders {
    const token = localStorage.getItem('auth_token');
    return new HttpHeaders({
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${token}`
    });
  }

  // Converte o modelo Character para o formato esperado pela API
  private convertToApiFormat(character: Character): any {
    // Mapeia a raça para o formato esperado pela API
    let race = '';
    let subRace = '';
    
    // Simplificando, podemos usar o index da raça como o valor da raça/subRaça
    // Na vida real, você precisaria mapear corretamente de acordo com os valores aceitos pela API
    if (character.race.index) {
      // Exemplo: half-elf -> MEIO_ELFO
      const raceMap: Record<string, {race: string, subRace?: string}> = {
        'elf': {race: 'ELFO', subRace: 'ELFO_ALTO'},
        'half-elf': {race: 'MEIO_ELFO'},
        'human': {race: 'HUMANO'},
        'dwarf': {race: 'ANAO', subRace: 'ANAO_DA_COLINA'},
        'halfling': {race: 'HALFLING', subRace: 'HALFLING_PES_LEVES'},
        'dragonborn': {race: 'DRACONATO'},
        'gnome': {race: 'GNOMO', subRace: 'GNOMO_DA_FLORESTA'},
        'half-orc': {race: 'MEIO_ORC'},
        'tiefling': {race: 'TIEFLING'}
      };
      
      const raceInfo = raceMap[character.race.index] || {race: 'HUMANO'};
      race = raceInfo.race;
      subRace = raceInfo.subRace || '';
    }
    
    // Mapeia a classe para o formato esperado pela API
    let charClass = '';
    if (character.class.index) {
      // Exemplo: warlock -> BRUXO
      const classMap: Record<string, string> = {
        'barbarian': 'BARBARO',
        'bard': 'BARDO',
        'cleric': 'CLERIGO',
        'druid': 'DRUIDA',
        'fighter': 'GUERREIRO',
        'monk': 'MONGE',
        'paladin': 'PALADINO',
        'ranger': 'GUARDIAO',
        'rogue': 'LADINO',
        'sorcerer': 'FEITICEIRO',
        'warlock': 'BRUXO',
        'wizard': 'MAGO'
      };
      
      charClass = classMap[character.class.index] || 'GUERREIRO';
    }
    
    // Mapeia skills para o formato esperado pela API
    // Por padrão, definimos todas como false
    const skills = {
      stStrength: false,
      stDexterity: false,
      stConstitution: false,
      stIntelligence: false,
      stWisdom: false,
      stCharisma: false,
      acrobatics: false,
      animalHandling: false,
      arcana: false,
      athletics: false,
      deception: false,
      history: false,
      insight: false,
      intimidation: false,
      investigation: false,
      medicine: false,
      nature: false,
      perception: false,
      performance: false,
      persuasion: false,
      religion: false,
      sleightOfHand: false,
      stealth: false,
      survival: false
    };
    
    // Se tiver proficiências em saving throws, mapeie-as
    if (character.proficiencies.savingThrows) {
      character.proficiencies.savingThrows.forEach(st => {
        if (st === 'strength') skills.stStrength = true;
        if (st === 'dexterity') skills.stDexterity = true;
        if (st === 'constitution') skills.stConstitution = true;
        if (st === 'intelligence') skills.stIntelligence = true;
        if (st === 'wisdom') skills.stWisdom = true;
        if (st === 'charisma') skills.stCharisma = true;
      });
    }
    
    // Se tiver proficiências em skills, mapeie-as (simplificado)
    if (character.proficiencies.skills) {
      character.proficiencies.skills.forEach(skill => {
        // Mapeamento simplificado, você precisará ajustar conforme sua estrutura real
        if (skills.hasOwnProperty(skill)) {
          (skills as any)[skill] = true;
        }
      });
    }
    
    // Constrói o objeto no formato esperado pela API
    return {
      name: character.name,
      race: race,
      subRace: subRace,
      charClass: charClass,
      inspiration: 0, // Valor padrão
      attributes: {
        strength: character.attributes.strength,
        dexterity: character.attributes.dexterity,
        constitution: character.attributes.constitution,
        intelligence: character.attributes.intelligence,
        wisdom: character.attributes.wisdom,
        charisma: character.attributes.charisma
      },
      skills: skills,
      progression: {
        alignment: character.alignment || 'Neutro'
      }
    };
  }

  // Cria um novo personagem
  createCharacter(character: Character): Observable<any> {
    // Adiciona userId do usuário logado
    character.userId = this.authService.getUserId();
    
    // Converte para o formato da API
    const apiCharacter = this.convertToApiFormat(character);
    
    // Log para depuração
    console.log('Enviando personagem para API:', JSON.stringify(apiCharacter));
    
    return this.http.post(`${this.baseUrl}/personagens`, apiCharacter, {
      headers: this.getAuthHeaders()
    }).pipe(
      tap(response => console.log('Resposta da API:', response)),
      catchError(error => {
        console.log('Erro detalhado da API:', error);
        if (error.error && error.error.message) {
          console.log('Mensagem de erro do servidor:', error.error.message);
        }
        return throwError(() => error);
      })
    );
  }

  // Lista todos os personagens do usuário logado
  listCharacters(): Observable<CharacterListItem[]> {
    const userId = this.authService.getUserId();
    return this.http.get<CharacterListItem[]>(`${this.baseUrl}/personagens?userId=${userId}`, {
      headers: this.getAuthHeaders()
    });
  }

  // Obtém um personagem específico
  getCharacter(id: string): Observable<Character> {
    return this.http.get<Character>(`${this.baseUrl}/personagens/${id}`, {
      headers: this.getAuthHeaders()
    });
  }

  // Atualiza um personagem existente
  updateCharacter(id: string, data: Partial<Character>): Observable<any> {
    // Para atualização, você também precisará converter para o formato da API
    // Esta é uma implementação simplificada
    const apiFormat = this.convertToApiFormat(data as Character);
    
    return this.http.put(`${this.baseUrl}/personagens/${id}`, apiFormat, {
      headers: this.getAuthHeaders()
    });
  }

  // Exclui um personagem
  deleteCharacter(id: string): Observable<any> {
    return this.http.delete(`${this.baseUrl}/personagens/${id}`, {
      headers: this.getAuthHeaders()
    });
  }

  // Calcula o bônus de atributo com base no valor
  calculateAttributeModifier(attributeValue: number): number {
    return Math.floor((attributeValue - 10) / 2);
  }

  // Calcula o bônus de proficiência com base no nível
  calculateProficiencyBonus(level: number): number {
    return Math.ceil(1 + (level / 4));
  }
}
